// Get data from the "Telegram Trigger" node
const telegramData = $('Telegram Trigger').item.json;

// Get an array of photos
const photos = telegramData.message.photo;

// If no photo is found, return an empty result
if (!photos || photos.length === 0) {
  return { json: { error: 'No photos found' } };
}

// Find the photo with the maximum width
const highestResPhoto = photos.reduce((max, photo) => {
  return photo.width > max.width ? photo : max;
}, photos[0]);

// Return ONLY the selected photo
return {
  json: highestResPhoto
};

